1	import { blobToRawUrl } from "./github/url.js";
2	import { waitForFileView, insertContainerAbove, setNativeViewVisible, type Mounted } from "./github/mount.js";
3	import { JsonlStreamDecoder } from "./parser/jsonl-stream.js";
4	import { isMetaRecord, isMessageRecord, isSupportedSchemaVersion, type MetaRecord } from "./parser/schema.js";
5	import { renderRoot, type RootApi } from "./render/root.js";
6	
7	type State = "init" | "loading" | "rendered" | "raw" | "degraded" | "error" | "disposed";
8	
9	export class Controller {
10	  private state: State = "init";
11	  private abort = new AbortController();
12	  private mounted: Mounted | null = null;
13	  private api: RootApi | null = null;
14	  private readonly blobUrl: string;
15	
16	  constructor(blobUrl: string) { this.blobUrl = blobUrl; }
17	
18	  async run(): Promise<void> {
19	    this.state = "loading";
20	    const nativeView = await waitForFileView();
21	    if (this.state === "disposed") return;
22	    if (!nativeView) { this.state = "degraded"; return; }
23	    this.mounted = insertContainerAbove(nativeView);
24	    try {
25	      await this.fetchAndRender();
26	    } catch (e) {
27	      if (this.state === "disposed") return;
28	      if ((e as Error).name === "AbortError") return;
29	      console.error("[show-me-your-prompt]", e);
30	      this.state = "degraded";
31	      this.dispose();
32	    }
33	  }
34	
35	  dispose(): void {
36	    if (this.state === "disposed") return;
37	    this.state = "disposed";
38	    this.abort.abort();
39	    this.mounted?.unmount();
40	    this.mounted = null;
41	  }
42	
43	  private async fetchAndRender(): Promise<void> {
44	    const raw = blobToRawUrl(this.blobUrl);
45	    if (!raw) { this.dispose(); return; }
46	    let resp: Response;
47	    try {
48	      resp = await fetch(raw, { signal: this.abort.signal });
49	    } catch (e) {
50	      this.showFetchError();
51	      return;
52	    }
53	    if (resp.status === 403) { this.dispose(); return; }
54	    if (!resp.ok || !resp.body) { this.showDegraded(`HTTP ${resp.status}`); return; }
55	
56	    const reader = resp.body.getReader();
57	    const dec = new JsonlStreamDecoder();
58	    let meta: MetaRecord | null = null;
59	
60	    while (true) {
61	      const { done, value } = await reader.read();
62	      if (done) break;
63	      const records = dec.push(value);
64	      if (!this.consume(records, (m) => (meta = m))) return;
65	      if (!meta) continue;
66	    }
67	    const tail = dec.flush();
68	    this.consume(tail, (m) => (meta = m));
69	
70	    if (!meta) {
71	      this.showDegraded("missing meta record");
72	    }
73	  }
74	
75	  private consume(records: unknown[], onMeta: (m: MetaRecord) => void): boolean {
76	    for (const r of records) {
77	      if (isMetaRecord(r)) {
78	        if (!isSupportedSchemaVersion(r.schema_version)) {
79	          this.showUnsupportedVersion(r);
80	          return false;
81	        }
82	        if (!this.api) {
83	          this.api = renderRoot(r, { onToggleRendered: (on) => this.setRendered(on) });
84	          this.mounted!.container.appendChild(this.api.element);
85	          this.state = "rendered";
86	          setNativeViewVisible(this.mounted!, false);
87	        }
88	        onMeta(r);
89	      } else if (isMessageRecord(r)) {
90	        this.api?.appendMessage(r);
91	      }
92	    }
93	    return true;
94	  }
95	
96	  private setRendered(on: boolean): void {
97	    if (!this.api || !this.mounted) return;
98	    this.api.element.style.display = on ? "" : "none";
99	    setNativeViewVisible(this.mounted, !on);
100	    this.api.setMode(on ? "rendered" : "raw");
101	    this.state = on ? "rendered" : "raw";
102	  }
103	
104	  private showFetchError(): void {
105	    if (!this.mounted) return;
106	    if (!this.api) {
107	      const fallbackMeta: MetaRecord = {
108	        type: "meta",
109	        schema_version: 1,
110	        source: "claude-code",
111	        exported_at: "",
112	        exported_by: "",
113	        title: ".prompttrace.jsonl",
114	        sanitization: { rules_applied: [], redaction_count: 0 },
115	      };
116	      this.api = renderRoot(fallbackMeta, { onToggleRendered: () => {} });
117	      this.mounted.container.appendChild(this.api.element);
118	    }
119	    this.api.showError("Failed to load .prompttrace.jsonl — network error", () => {
120	      this.abort = new AbortController();
121	      this.fetchAndRender().catch((e) => console.error(e));
122	    });
123	    this.state = "error";
124	  }
125	
126	  private showUnsupportedVersion(r: MetaRecord): void {
127	    if (!this.mounted) return;
