6	interface RawEntry {
7	  type: string;
8	  uuid: string;
9	  parentUuid: string | null;
10	  timestamp: string;
11	  cwd?: string;
12	  message: { role: string; content: string | RawBlock[] };
13	}
14	
15	export interface ParseSessionResult {
16	  session: Session;
17	  parseErrors: { line: number; message: string }[];
18	}
19	
20	export function parseSessionFile(raw: string, sourceSessionId: string): ParseSessionResult {
21	  const { records, errors } = parseJsonl(raw);
22	  const messages: Message[] = [];
23	  const parseErrors: { line: number; message: string }[] = errors.map((e) => ({
24	    line: e.line,
25	    message: e.message,
26	  }));
27	  let cwd: string | null = null;
28	  for (let i = 0; i < records.length; i++) {
29	    try {
30	      const entry = records[i] as RawEntry;
31	      if (!entry || typeof entry !== 'object') {
32	        parseErrors.push({ line: -1, message: `record ${i}: not an object` });
33	        continue;
34	      }
35	      if (entry.type !== 'user' && entry.type !== 'assistant') continue;
36	      if (!entry.message || entry.uuid == null) {
37	        parseErrors.push({ line: -1, message: `record ${i}: missing message or uuid` });
38	        continue;
39	      }
40	      if (entry.cwd && !cwd) cwd = entry.cwd;
41	      const content = normalizeContent(entry.message.content);
42	      messages.push({
43	        uuid: entry.uuid,
44	        parentUuid: entry.parentUuid ?? null,
45	        role: entry.type === 'user' ? 'user' : 'assistant',
46	        timestamp: entry.timestamp,
47	        content,
48	      });
49	    } catch (err) {
50	      const message = err instanceof Error ? err.message : String(err);
51	      parseErrors.push({ line: -1, message: `record ${i}: ${message}` });
52	    }
53	  }
54	  const meta: SessionMeta = {
55	    sourceSessionId,
56	    cwd,
57	    firstMessagePreview: firstText(messages).slice(0, 120),
58	    messageCount: messages.length,
59	    startedAt: messages[0]?.timestamp ?? '',
60	    endedAt: messages[messages.length - 1]?.timestamp ?? '',
61	  };
62	  return {
63	    session: { meta, messages },
64	    parseErrors,
65	  };
66	}
67	
68	function normalizeContent(raw: string | ContentBlock[] | RawBlock[]): ContentBlock[] {
69	  if (typeof raw === 'string') return [{ type: 'text', text: raw }];
70	  if (!Array.isArray(raw)) return [];
71	  const out: ContentBlock[] = [];
72	  for (const b of raw) {
73	    if (!b || typeof b !== 'object') continue;
74	    if (b.type === 'text' && typeof b.text === 'string') {
75	      out.push({ type: 'text', text: b.text });
76	    } else if (b.type === 'tool_use' && typeof b.id === 'string' && typeof b.name === 'string') {
77	      out.push({ type: 'tool_use', id: b.id, name: b.name, input: b.input });
78	    } else if (b.type === 'tool_result' && typeof b.tool_use_id === 'string') {
79	      const content = (b as { content?: unknown; output?: unknown }).content ?? (b as { output?: unknown }).output;
80	      const output =
81	        typeof content === 'string'
