1	const CONTAINER_ID = "prompttrace-container";
2	
3	const SELECTORS = [
4	  '[data-testid="code-view"]',
5	  'react-app[app-name="react-code-view"]',
6	];
7	
8	export async function waitForFileView(timeoutMs = 3000): Promise<HTMLElement | null> {
9	  const deadline = Date.now() + timeoutMs;
10	  return new Promise((resolve) => {
11	    const check = () => {
12	      for (const sel of SELECTORS) {
13	        const el = document.querySelector(sel) as HTMLElement | null;
14	        if (el) return resolve(el);
15	      }
16	      if (Date.now() > deadline) return resolve(null);
17	      setTimeout(check, 100);
18	    };
19	    check();
20	  });
21	}
22	
23	export interface Mounted {
24	  container: HTMLElement;
25	  nativeView: HTMLElement;
26	  unmount: () => void;
27	}
28	
29	export function mountIntoFileView(codeView: HTMLElement): Mounted {
30	  removeExistingContainer();
31	  const parent = codeView.parentElement;
32	  if (!parent) throw new Error("code-view has no parent");
33	  const container = document.createElement("div");
34	  container.id = CONTAINER_ID;
35	  parent.insertBefore(container, codeView);
36	  const originalDisplay = codeView.style.display;
37	  codeView.style.display = "none";
38	  const unmount = () => {
39	    container.remove();
40	    codeView.style.display = originalDisplay;
41	  };
42	  return { container, nativeView: codeView, unmount };
43	}
44	
45	export function setNativeViewVisible(m: Mounted, visible: boolean): void {
46	  m.nativeView.style.display = visible ? "" : "none";
47	}
48	
49	function removeExistingContainer(): void {
50	  document.getElementById(CONTAINER_ID)?.remove();
51	}
52

