it("prefers react-app[app-name=code-view] when both it and #repo-content-pjax-container exist", async () => {
  const dom = new JSDOM(
    `<!doctype html><html><body>
      <main>
        <div id="repo-content-pjax-container">
          <react-app app-name="code-view">ra</react-app>
        </div>
      </main>
